```python
def classify_response(status_code, body):
    if status_code == 200 and body.get("ok") is True:
        return "PASS"
    elif status_code == 404:
        return "FAIL: resource not found"
    elif 500 <= status_code <= 599:
        return "FAIL: server error " + str(status_code)
    else:
        return "FAIL: unexpected status " + str(status_code)

print(classify_response(200, {"ok": True}))   # PASS
print(classify_response(404, {}))             # FAIL: resource not found
print(classify_response(503, {}))             # FAIL: server error 503
```
